```ts
export declare function layout<TLayout extends RequestInfo = RequestInfo, Routes extends readonly Route<any>[] = readonly Route<any>[]>(
  LayoutComponent: React.FC<LayoutProps<TLayout>>,
  routes: Routes
): Routes;
```

### `prefix(prefixPath, routes)` → routes

Prepends a path prefix to a group of routes. Supports nested arrays and handles middleware scoping.

### `except(handler)` → `ExceptHandler`

Global error handler. Catches errors from routes, middleware, and RSC actions.

```ts
export declare function except<T extends RequestInfo = RequestInfo>(
  handler: (error: unknown, requestInfo: T) => MaybePromise<React.JSX.Element | Response | void>
): ExceptHandler<T>;
```

Except handlers can optionally have a `pathPattern` to scope them. They are searched backwards from the error site.

---

## 3. Middleware System

### Global Middleware (runs on EVERY request)

Simply place a function at the top of your `defineApp` routes array:

```ts
export default defineApp([
  // Global middleware — runs for every request
  async ({ request, ctx, response, cf, rw }) => {
    // Add security headers
    response.headers.set("X-Frame-Options", "DENY");
    // Set up DB, sessions, auth, etc.
    ctx.user = await authenticateUser(request);
  },
  render(Document, [
    route("/", HomePage),
    route("/about", AboutPage),
  ]),
]);
```

Middleware receives the full `RequestInfo` object (see below). It can:
- Return `void` → continues to next middleware/route
- Return a `Response` → short-circuits, response sent immediately
- Return a `React.JSX.Element` → renders that element as the response
- Throw an error → caught by `except` handlers

### Route-Specific Middleware

Pass an array where all but the last element are middleware:

```ts
route("/admin", [isAuthenticated, isAdmin, () => <AdminDashboard />])
//                ^^^^^^^^^^^^^^  ^^^^^^^  middleware
//                                 ^^^^^^^^^^^^^^^^^^^^^^^^  final handler
```

### Middleware Signature

```ts
type RouteMiddleware<T extends RequestInfo = RequestInfo> = (
  requestInfo: T
) => MaybePromise<React.JSX.Element | Response | void>;
```

---

## 4. Custom HTTP Handlers/Routes (non-React)

You can return a `Response` directly from any route handler:

```ts
// Plain text
route("/api/status", () => new Response("OK", { status: 200 }));

// JSON
route("/api/users/:id", ({ params }) => {
  return Response.json({ id: params.id, name: "John" });
});

// Method-based API
route("/api/posts", {
  get: () => Response.json(posts),
  post: async ({ request }) => {
    const body = await request.json();
    return Response.json({ created: true }, { status: 201 });
  },
});
```

---

## 5. Accessing Worker Environment/Bindings

### The `RequestInfo` Object

Available in every route handler, middleware, and `except` handler:

```ts
interface RequestInfo<Params = any, AppContext = DefaultAppContext> {
  request: Request;          // The incoming Request
  path: string;              // Normalized path (always ends with /)
  params: Params;            // Route params (e.g., { id: "123" })
  ctx: AppContext;           // Mutable context bag — populate in middleware
  rw: RwContext;             // Internal SDK context (Document, nonce, etc.)
  cf: ExecutionContext;      // Cloudflare ExecutionContext (waitUntil, passThroughOnException, props)
  response: ResponseInit & { headers: Headers };  // Mutable response init
  isAction: boolean;         // Whether this is an RSC action request
}
```

### How to Access `env` Bindings (KV, D1, DO, etc.)

**From within route handlers/middleware**, you access the `env` bindings through the `requestInfo.ctx` pattern. The `env` object from the Cloudflare Worker's `fetch(request, env, cf)` is **not directly passed** to route handlers. Instead, you must populate `ctx` in a global middleware:

```ts
export default defineApp([
  // Populate ctx with env bindings in global middleware
  ({ ctx }) => {
    // You need to capture env here. Since defineApp's fetch receives (request, env, cf),
    // the SDK stores request/cf but NOT env on RequestInfo.
    // The pattern is to use a closure or module-level variable:
  },
  // ...
]);
```

**The actual mechanism:** The `defineApp` function creates a `fetch` handler that receives `(request, env, cf)`. Looking at `dist/runtime/server.js`, the `env` object is used internally for `env.ASSETS.fetch()` but is **not stored on the RequestInfo**. 

**To access KV, D1, DO, R2, etc., you need to capture `env` in a closure.** The recommended pattern is to use a module-level variable or create a wrapper:

```ts
// worker.tsx
let workerEnv: Env;

export default {
  async fetch(request: Request, env: Env, ctx: ExecutionContext) {
    workerEnv = env;
    const app = defineApp([/* routes */]);
    return app.fetch(request, env, ctx);
  }
};
```

Or more idiomatically, populate `ctx` via middleware that captures `env`:

```ts
// The defineApp fetch handler receives env, but you need to make it available.
// One approach: wrap defineApp to inject env into ctx:

function createApp(env: Env) {
  return defineApp([
    ({ ctx }) => {
      // Make env available on ctx
      (ctx as any).env = env;
    },
    render(Document, [
      route("/", HomePage),
      route("/api/data", async ({ ctx }) => {
        const env = (ctx as any).env as Env;
        const value = await env.MY_KV.get("key");
        return Response.json({ value });
      }),
    ]),
  ]);
}

export default {
  async fetch(request: Request, env: Env, cf: ExecutionContext) {
    const app = createApp(env);
    return app.fetch(request, env, cf);
  }
};
```

**For server functions (`serverQuery`/`serverAction`)**, you can access `request` and `ctx` via the `requestInfo` global:

```ts
import { requestInfo } from "rwsdk/worker";

export const getUser = serverQuery(async (id: string) => {
  const { request, ctx } = requestInfo;
  // ctx.env would have your bindings if populated in middleware
});
```

### `requestInfo` Global (from `rwsdk/worker`)

```ts
// dist/runtime/requestInfo/worker.js
export const requestInfo: DefaultRequestInfo;  // Proxy object — each property is a getter
export function getRequestInfo(): RequestInfo;  // Returns the current RequestInfo store
export function runWithRequestInfo<Result>(nextRequestInfo, fn): Result;
export function runWithRequestInfoOverrides<Result>(overrides, fn): Result;
```

The `requestInfo` export is a frozen proxy where each property (`request`, `params`, `ctx`, `rw`, `cf`, `response`) is a getter that reads from `AsyncLocalStorage`. This means it's only available during a request lifecycle.

---

## 6. Server Functions (`rwsdk/worker`)

### `serverQuery(fn | [...interruptors, fn], options?)`

```ts
export declare function serverQuery<TArgs extends any[], TResult>(
  fnsOrFn: ServerFunction<TArgs, TResult> | [...Interruptor<TArgs>[], ServerFunction<TArgs, TResult>],
  options?: ServerFunctionOptions  // { method?: "GET" | "POST" }
): WrappedServerFunction<TArgs, TResult>;
```

- Default method: `GET`
- Returns data only, does NOT re-render the page
- Must be in a `"use server"` file

### `serverAction(fn | [...interruptors, fn], options?)`

```ts
export declare function serverAction<TArgs extends any[], TResult>(
  fnsOrFn: ServerFunction<TArgs, TResult> | [...Interruptor<TArgs>[], ServerFunction<TArgs, TResult>],
  options?: ServerFunctionOptions  // { method?: "GET" | "POST" }
): WrappedServerFunction<TArgs, TResult>;
```

- Default method: `POST`
- Re-renders the page with new server state

### Interruptors

```ts
type Interruptor<TArgs extends any[] = any[]> = (context: {
  request: Request;
  ctx: Record<string, any>;
  args: TArgs;
}) => Promise<Response | void> | Response | void;
```

Interruptors run BEFORE the server function. If they return a `Response`, it short-circuits.

### `registerServerFunctionWrap(wrap)`

```ts
export declare function registerServerFunctionWrap(wrap: ServerFunctionWrap): void;

type ServerFunctionWrap = (fn: Function, args: any[], type: "action" | "query") => Promise<any>;
```

Wraps every server action/query call (e.g., for Sentry instrumentation).

---

## 7. Error Handling

### `ErrorResponse` class (from `rwsdk/worker`)

```ts
export declare class ErrorResponse extends Error {
  code: number;
  message: string;
  constructor(code: number, message: string);
}
```

### `except(handler)` — Global Error Handler

```ts
except((error, requestInfo) => {
  if (error instanceof ErrorResponse && error.code === 404) {
    return <NotFoundPage />;
  }
  return new Response("Internal Error", { status: 500 });
});
```

---

## 8. Links API (`rwsdk/router`)

```ts
export declare function linkFor<App>(): AppLink<App>;
export declare function createLinks<App>(_app?: App): AppLink<App>;
export declare function defineLinks<App>(): AppLink<App>;
export declare function defineLinks<const T extends readonly string[]>(routes: T): LinkFunction<T[number]>;
```

---

## 9. Complete Worker Example

```ts
// src/worker.tsx
import { defineApp, render, route, prefix, except, index } from "rwsdk/router";
import { Document } from "./Document";

export default defineApp([
  // 1. Global middleware — runs on every request
  async ({ request, response, ctx }) => {
    response.headers.set("X-Content-Type-Options", "nosniff");
  },

  // 2. Routes wrapped with Document
  render(Document, [
    index(() => <HomePage />),
    route("/about", () => <AboutPage />),

    // Route with middleware array
    route("/admin", [requireAuth, () => <AdminDashboard />]),

    // API route returning Response
    route("/api/health", () => Response.json({ status: "ok" })),

    // Method-based API
    route("/api/users", {
      get: () => Response.json(users),
      post: async ({ request }) => {
        const body = await request.json();
        return Response.json({ created: true }, { status: 201 });
      },
    }),

    // Prefixed routes
    prefix("/blog", [
      route("/", () => <BlogIndex />),
      route("/:slug", ({ params }) => <BlogPost slug={params.slug} />),
    ]),
  ]),

  // 3. Global error handler
  except((error, { request }) => {
    console.error(`Error for ${request.url}:`, error);
    return new Response("Server Error", { status: 500 });
  }),
]);
```

