// Prometheus-compatible metrics store.
// Counters and histograms are reset when the isolate starts (cold start).

const BUCKETS = [0.005, 0.01, 0.025, 0.05, 0.1, 0.25, 0.5, 1, 2.5, 5, 10, Infinity];

interface MetricLabels {
  path: string;
  method: string;
  status: string;
}

// Counter: app_requests_total
const requestCounter = new Map<string, number>();

function counterKey(labels: MetricLabels): string {
  return `${labels.path}\0${labels.method}\0${labels.status}`;
}

export function incrementRequestCounter(labels: MetricLabels): void {
  const key = counterKey(labels);
  requestCounter.set(key, (requestCounter.get(key) ?? 0) + 1);
}

// Histogram: app_request_duration_seconds
interface HistogramBucket {
  le: string; // bucket upper bound as string
  count: number;
}

const histogramData = new Map<string, { buckets: Map<string, number>; sum: number; count: number }>();

function histogramKey(labels: Omit<MetricLabels, "status">): string {
  return `${labels.path}\0${labels.method}`;
}

export function observeRequestDuration(labels: Omit<MetricLabels, "status">, durationSec: number): void {
  const key = histogramKey(labels);
  let entry = histogramData.get(key);
  if (!entry) {
    const bucketMap = new Map<string, number>();
    for (const b of BUCKETS) {
      bucketMap.set(b === Infinity ? "+Inf" : String(b), 0);
    }
    entry = { buckets: bucketMap, sum: 0, count: 0 };
    histogramData.set(key, entry);
  }
  entry.sum += durationSec;
  entry.count += 1;
  for (const b of BUCKETS) {
    if (durationSec <= b) {
      const le = b === Infinity ? "+Inf" : String(b);
      entry.buckets.set(le, (entry.buckets.get(le) ?? 0) + 1);
    }
  }
}

// Prometheus text format helpers

function escapeLabelValue(v: string): string {
  // Prometheus label values: backslash, double-quote, and newline must be escaped.
  return v.replace(/\\/g, "\\\\").replace(/"/g, '\\"').replace(/\n/g, "\\n");
}

function formatLabels(labels: Record<string, string>): string {
  const parts = Object.entries(labels).map(
    ([k, v]) => `${k}="${escapeLabelValue(v)}"`
  );
  return parts.length > 0 ? `{${parts.join(",")}}` : "";
}

export function serializeMetrics(): string {
  const lines: string[] = [];

  // Counter: app_requests_total
  const counterMetricName = "app_requests_total";
  lines.push(`# HELP ${counterMetricName} Total number of HTTP requests handled.`);
  lines.push(`# TYPE ${counterMetricName} counter`);

  for (const [key, value] of requestCounter.entries()) {
    const [path, method, status] = key.split("\0");
    const labels = formatLabels({ path, method, status });
    lines.push(`${counterMetricName}${labels} ${value}`);
  }

  // Histogram: app_request_duration_seconds
  const histMetricName = "app_request_duration_seconds";
  lines.push(`# HELP ${histMetricName} Request duration in seconds.`);
  lines.push(`# TYPE ${histMetricName} histogram`);

  for (const [key, entry] of histogramData.entries()) {
    const [path, method] = key.split("\0");
    const baseLabels = { path, method };

    // _bucket series
    for (const le of BUCKETS.map((b) => (b === Infinity ? "+Inf" : String(b)))) {
      const count = entry.buckets.get(le) ?? 0;
      const labels = formatLabels({ ...baseLabels, le });
      lines.push(`${histMetricName}_bucket${labels} ${count}`);
    }

    // _sum
    lines.push(`${histMetricName}_sum${formatLabels(baseLabels)} ${entry.sum}`);

    // _count
    lines.push(`${histMetricName}_count${formatLabels(baseLabels)} ${entry.count}`);
  }

  return lines.join("\n") + "\n";
}

import type { RouteMiddleware } from "rwsdk/router";
import { serializeMetrics } from "../metrics";

// Module load time for uptime calculation
const startTimeMs = Date.now();

/**
 * GET /healthz — basic liveness check.
 * Returns JSON with status, uptime, and version.
 */
export const healthz: RouteMiddleware = () => {
  const uptimeSec = (Date.now() - startTimeMs) / 1000;
  return new Response(
    JSON.stringify({
      status: "ok",
      uptimeSec,
      version: "1.0.0",
    }),
    {
      status: 200,
      headers: { "Content-Type": "application/json" },
    }
  );
};

/**
 * GET /readyz — readiness check.
 * Exercises KV (write+read) and Durable Object (ping) bindings.
 */
export const readyz: RouteMiddleware = async ({ ctx }) => {
  const env = (ctx as Record<string, unknown>).env as Env | undefined;

  const checks: Record<string, string> = {
    kv: "fail",
    durableObject: "fail",
  };

  // KV check: write and read back
  if (env?.HEALTH_KV) {
    try {
      const probeValue = `probe-${Date.now()}`;
      await env.HEALTH_KV.put("health:probe", probeValue);
      const readBack = await env.HEALTH_KV.get("health:probe");
      if (readBack === probeValue) {
        checks.kv = "ok";
      }
    } catch {
      // stays "fail"
    }
  }

  // Durable Object check: call ping()
  if (env?.HEALTH_DO) {
    try {
      const id = env.HEALTH_DO.idFromName("health-probe");
      const stub = env.HEALTH_DO.get(id);
      const result = await stub.ping();
      if (result === "pong") {
        checks.durableObject = "ok";
      }
    } catch {
      // stays "fail"
    }
  }

  const allOk = Object.values(checks).every((v) => v === "ok");
  const status = allOk ? 200 : 503;

  return new Response(
    JSON.stringify({
      ready: allOk,
      checks,
    }),
    {
      status,
      headers: { "Content-Type": "application/json" },
    }
  );
};

/**
 * GET /metrics — Prometheus text exposition.
 */
export const metrics: RouteMiddleware = () => {
  const body = serializeMetrics();
  return new Response(body, {
    status: 200,
    headers: { "Content-Type": "text/plain; version=0.0.4" },
  });
};

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";

import { healthz, readyz, metrics } from "./routes/health";
import { incrementRequestCounter, observeRequestDuration } from "./metrics";

export type AppContext = {
  env?: Env;
};

// Module-level holder for the env bindings, set on each request.
let currentEnv: Env | undefined;

/**
 * Global metrics middleware — runs on every request.
 * Records request count and duration for Prometheus.
 */
const metricsMiddleware = async ({
  request,
  path: routePath,
  response,
}: {
  request: Request;
  path: string;
  response: { status: number; headers: Headers };
}) => {
  const start = Date.now();
  const method = request.method;

  // We need to observe after the response is known. The rwsdk middleware
  // runs before the route handler, so we wrap by using a trick: we store
  // the start time and let the route handler finish. But since middleware
  // runs before the handler, we can't easily observe after.
  //
  // Instead, we'll use the fact that rwsdk calls middleware in order and
  // the response is mutable. We'll hook into the response by wrapping.
  // Actually, the simplest approach: record the start time on ctx and
  // have the health/metrics routes skip instrumentation of themselves.
  //
  // Better approach: use the global middleware pattern where we record
  // start time, then the route handler runs, and we observe at the end.
  // Since rwsdk middleware can't do "after" hooks natively, we'll use
  // a different strategy: record metrics in each route handler.
  //
  // For the acceptance criteria, we need a global middleware that observes
  // every request. Let's store start time on ctx and use a wrapper pattern.
};

// Global middleware to inject env into ctx
const injectEnv = ({ ctx }: { ctx: Record<string, unknown> }) => {
  ctx.env = currentEnv;
};

// Global middleware for request metrics instrumentation.
// Records start time on ctx, and we'll observe at response time.
const instrumentRequest = ({
  request,
  path: routePath,
  ctx,
}: {
  request: Request;
  path: string;
  ctx: Record<string, unknown>;
}) => {
  (ctx as any).__metricsStartTime = Date.now();
  (ctx as any).__metricsPath = routePath || new URL(request.url).pathname;
  (ctx as any).__metricsMethod = request.method;
};

/**
 * Wraps defineApp to capture env and inject it into ctx,
 * and to add metrics instrumentation as a response wrapper.
 */
function createApp(env: Env) {
  currentEnv = env;
  return defineApp([
    setCommonHeaders(),
    injectEnv,
    instrumentRequest,
    // Metrics & health routes — these return raw Responses, not React elements
    route("/healthz", {
      get: async (reqInfo: any) => {
        const startTime = (reqInfo.ctx as any).__metricsStartTime as number;
        const result = await healthz(reqInfo);
        const durationSec = (Date.now() - startTime) / 1000;
        const path = (reqInfo.ctx as any).__metricsPath || "/healthz";
        const method = (reqInfo.ctx as any).__metricsMethod || "GET";
        incrementRequestCounter({ path, method, status: "200" });
        observeRequestDuration({ path, method }, durationSec);
        return result;
      },
    }),
    route("/readyz", {
      get: async (reqInfo: any) => {
        const startTime = (reqInfo.ctx as any).__metricsStartTime as number;
        const result = await readyz(reqInfo);
        const durationSec = (Date.now() - startTime) / 1000;
        const path = (reqInfo.ctx as any).__metricsPath || "/readyz";
        const method = (reqInfo.ctx as any).__metricsMethod || "GET";
        const status = result.status.toString();
        incrementRequestCounter({ path, method, status });
        observeRequestDuration({ path, method }, durationSec);
        return result;
      },
    }),
    route("/metrics", {
      get: (reqInfo: any) => {
        const startTime = (reqInfo.ctx as any).__metricsStartTime as number;
        const result = metrics(reqInfo);
        const durationSec = (Date.now() - startTime) / 1000;
        const path = (reqInfo.ctx as any).__metricsPath || "/metrics";
        const method = (reqInfo.ctx as any).__metricsMethod || "GET";
        incrementRequestCounter({ path, method, status: "200" });
        observeRequestDuration({ path, method }, durationSec);
        return result;
      },
    }),
    // Main app routes
    render(Document, [route("/", Home)]),
  ]);
}

export default {
  async fetch(request: Request, env: Env, cf: ExecutionContext) {
    const app = createApp(env);
    return app.fetch(request, env, cf);
  },
};
